// src/components/ProductCard/index.jsx (Обновленный код)

import React from 'react';
import { Link } from 'react-router-dom';
import { useDispatch } from 'react-redux'; // <-- Импортируем useDispatch
import { addToCart } from '../../store/slices/cartSlice'; // <-- Импортируем экшен
import { getImageUrl } from '../../utils/fixUrl';
import Button from '../UI/Button'; 
import s from './ProductCard.module.css';

const ProductCard = ({ id, title, price, discont_price, image }) => { // <-- Убедись, что имя поля тут правильное
  const dispatch = useDispatch(); // Инициализация диспетчера

  const imageUrl = getImageUrl(image);

  const isDiscounted = discont_price < price && discont_price !== null;
  const discountPercent = isDiscounted 
    ? Math.round(((price - discont_price) / price) * 100) 
    : 0;

  // Функция обработки добавления в корзину
  const handleAddToCart = (e) => {
    e.preventDefault(); // Предотвращаем переход по ссылке при клике на кнопку
    e.stopPropagation(); // Предотвращаем всплытие события

    // Диспатчим экшен, передавая все необходимые данные о товаре
    dispatch(addToCart({
      id,
      title,
      price, // Исходная цена
      image,
      discont_price // Цена со скидкой
    }));

    // Опционально: можно показать уведомление, что товар добавлен
    console.log(`Товар "${title}" добавлен в корзину.`);
  };

  return (
    <div className={s.card}>
      <Link to={`/products/${id}`} className={s.link}>
        {/* ... (Остальная верстка: изображение, заголовок, цены) ... */}
        <div className={s.imageWrapper}>
          <img src={imageUrl} alt={title} className={s.image} />
          {isDiscounted && (
            <div className={s.discountTag}>
              -{discountPercent}%
            </div>
          )}
        </div>
        <h3 className={s.title}>{title}</h3>
      </Link>

      <div className={s.priceBlock}>
        <p className={s.currentPrice}>
            {isDiscounted ? discont_price : price} $
        </p>
        {isDiscounted && <p className={s.originalPrice}>{price} $</p>}
      </div>

      <Button 
        type="primary" 
        onClick={handleAddToCart} // <-- Подключаем обработчик
        className={s.cartButton}
      >
        В корзину
      </Button>
    </div>
  );
};

export default ProductCard;
